import React from "react";
import './App.css'
import Projects from "./Projects.js"
import Home from "./Home.js"
import Resume from './Resume.js'
import Work from './Work.js'
import LinkedinLogo from './assets/linkedinlogo.png';
import GithubLogo from './assets/githublogo.png';
import GmailLogo from './assets/gmaillogo.png';
import JoshuaTreeImg from './assets/joshuatree.png';
import {useState} from 'react';
import {
    BrowserRouter as Router,
    Switch,
    Route,
    Link
} from "react-router-dom";
const routes = [
    {
        path: "/",
        exact: true,
        main: () => <Home/>
    },
    {
        path: "/resume",
        main: () => <Resume/>
    },
    {
        path: "/work",
        main: () => <Work/>
    },
    {
        path: "/Projects",
        main: () =>  <Projects/>
    }
];

function App() {
    return (
        <Router>
            <div>
                <div className= "header">
                    <h1 className="title">nathan lutz
                        <a href ="https://github.com/nathanlutz"><img src={GithubLogo} style= {{"height":"27px", "margin-left":"20px"}} alt="Github" /></a>
                    <a href ="https://www.linkedin.com/in/nathanlutz1"><img src={LinkedinLogo} style= {{"height":"27px", "margin-left":"5px"}} alt="LinkedIn" /></a>
                    <a href ="mailto:nathal@berkeley.edu"><img src={GmailLogo} style= {{"height":"27px", "margin-left":"5px"}} alt="Logo" /></a>
                    </h1>
                </div>
                <div className= "header" >
                    <Link className="navBarButton" to="/">Home</Link>
                    <Link className="navBarButton" to="/work">Work</Link>
                    <Link className="navBarButton" to="/projects">Projects</Link>
                    <Link className="navBarButton" to="/resume">Resume</Link>

                </div>
                <div>
                    <Switch>
                        {routes.map((route, index) => (
                            <Route
                                key={index}
                                path={route.path}
                                exact={route.exact}
                                children={<route.main />}
                            />
                        ))}
                    </Switch>
                </div>
            </div>
        </Router>
    );
}
export default App;

